import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  世界动态: z.object({
    时间: z.string().prefault('待初始化'),
    天下大势: z.string().prefault('待初始化'),
    当前危机: z.string().prefault('暂无'),
    周室威信: z.object({
      数值: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      文字描述: z.string().prefault('待初始化')
    }).prefault({}),
    市井动态: z.string().prefault('待初始化'),
    美人动向: z.string().prefault('暂无')
  }).prefault({}),

  风评舆论: z.object({
    列国风评: z.record(z.string(), z.object({
      具体评价: z.string(),
      态度: z.enum(['敌视', '防备', '中立', '拉拢', '敬畏'])
    })).prefault({}),
    百家态度: z.record(z.string(), z.object({
      具体评价: z.string(),
      态度: z.enum(['敌视', '排斥', '中立', '赞赏', '尊崇'])
    })).prefault({}),
    阶级评价: z.record(z.string(), z.object({
      具体评价: z.string(),
      数值: z.coerce.number().transform(v => _.clamp(v, -100, 100))
    })).prefault({})
  }).prefault({}),

  个人状态: z.object({
    姓名: z.string().prefault('待初始化'),
    年龄: z.coerce.number().prefault(15),
    表字: z.string().prefault('无'),
    阶级: z.string().prefault('待初始化'),
    官职: z.string().prefault('无'),
    从属: z.string().prefault('暂无'),
    威望: z.object({
      数值: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      文字描述: z.string().prefault('待初始化')
    }).prefault({}),
    属性: z.record(
      z.enum(['品行', '健康', '谋略', '政治', '统帅', '辩才']),
      z.object({
        数值: z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0)
      })
    ).prefault({}),
    功绩: z.record(z.string(), z.string()).transform(data => {
      return _(data).entries().takeRight(10).fromPairs().value();
    }).prefault({}),
    尊称: z.record(z.string(), z.string()).prefault({})
  }).prefault({}),

  势力与军事: z.object({
    势力: z.object({
      状况: z.enum(['执掌势力', '依附势力', '自立山头', '暂无']).prefault('暂无'),
      名称: z.string().prefault('无'),
      领袖: z.string().prefault('无'),
      动态: z.string().prefault('无')
    }).prefault({}),
    部队: z.record(z.string(), z.object({
      将领: z.string(),
      驻地: z.string(),
      数量: z.coerce.number(),
      士气: z.enum(['低落', '疲软', '平稳', '振奋', '昂扬']),
      训练: z.enum(['疏于操练', '初成行列', '进退有度', '号令严明', '习战精熟']),
      装备: z.enum(['简陋', '粗备', '齐整', '精良', '锐利']),
      补给状况: z.enum(['补给充足', '补给示警', '缺粮']),
      忠诚状况: z.enum(['忠诚', '恪职', '摇摆', '叛乱']),
      评价: z.string().describe('外界或主将对该部队的评价'),
      动态: z.string()
    })).prefault({}),
    部下: z.record(z.string(), z.object({
      官职: z.string(),
      关系: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      评价: z.string()
    })).prefault({})
  }).prefault({}),

  资产与人际: z.object({
    产业: z.record(z.string(), z.object({
      收入: z.coerce.number().prefault(0),
      支出: z.coerce.number().prefault(0),
      单位: z.enum(['石', '金']).prefault('石')
    })).prefault({}),
    储备: z.object({
      粮食_石: z.coerce.number().prefault(0),
      金钱_金: z.coerce.number().prefault(0)
    }).prefault({}),
    宗族: z.object({
      名称: z.string().prefault('无'),
      领袖: z.string().prefault('无'),
      等级: z.string().prefault('无'),
      动态: z.string().prefault('无'),
      成员: z.record(z.string(), z.object({
        官职: z.string(),
        关系: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
        评价: z.string()
      })).prefault({})
    }).prefault({}),
    人际关系: z.record(z.string(), z.object({
      关系描述: z.string(),
      评价: z.string()
    })).prefault({})
  }).prefault({}),

  后宫与子嗣: z.object({
    后宫动向: z.string().prefault('暂无'),
    后宫: z.record(z.string(), z.object({
      关系: z.string(),
      年龄: z.coerce.number(),
      外貌: z.string(),
      特质: z.string(),
      好感: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      宠爱: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      性爱次数: z.object({
        口: z.coerce.number().prefault(0),
        手: z.coerce.number().prefault(0),
        足: z.coerce.number().prefault(0),
        乳: z.coerce.number().prefault(0),
        穴: z.coerce.number().prefault(0),
        庭: z.coerce.number().prefault(0)
      }).prefault({})
    })).prefault({}),
    子嗣动向: z.string().prefault('暂无'),
    子嗣: z.record(z.string(), z.object({
      关系: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      评价: z.string()
    })).prefault({})
  }).prefault({})
});

$(() => {
  registerMvuSchema(Schema);
})

