<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <title>史书留名 - 极致横版（落款在下）</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            /* 优先使用宋体/明体等古籍常用字体 */
            font-family: 'STSong', 'SimSun', 'Noto Serif SC', 'Source Han Serif SC', serif;
            background: transparent;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 10px;
        }

        /* 史书外框：高度大幅压缩的横向折页 */
        .history-scroll {
            width: 100%;
            max-width: 700px;
            min-height: 120px;
            /* 逼真的旧纸张背景 */
            background-color: #eaddc5;
            background-image:
                linear-gradient(90deg, transparent 0%, rgba(200, 180, 140, 0.1) 50%, transparent 100%),
                linear-gradient(0deg, rgba(160, 130, 90, 0.05) 0%, transparent 10%, transparent 90%, rgba(160, 130, 90, 0.05) 100%);
            border-radius: 2px 6px 6px 2px;
            box-shadow:
                -3px 4px 10px rgba(0,0,0,0.2),
                inset 0 0 30px rgba(184, 142, 94, 0.15);
            position: relative;
            /* 保持左侧装订线空间，底部稍微留一点给落款 */
            padding: 20px 30px 20px 70px;
            display: flex;
            flex-direction: column;
            justify-content: center;
        }

        /* 仿线装书的打孔和丝线 */
        .binding-holes {
            position: absolute;
            left: 15px;
            top: 15%;
            bottom: 15%;
            width: 10px;
            display: flex;
            flex-direction: column;
            justify-content: space-between;
        }
        .hole {
            width: 7px;
            height: 10px;
            background-color: #2a221a;
            border-radius: 50%;
            box-shadow: inset 1px 1px 2px rgba(0,0,0,0.8), 0 1px 1px rgba(255,255,255,0.4);
            position: relative;
        }
        /* 穿过孔的红线 */
        .hole::after {
            content: '';
            position: absolute;
            width: 2px;
            height: 25px;
            background-color: #7a2626;
            left: 2.5px;
            top: -7.5px;
            z-index: 1;
            box-shadow: 1px 0 2px rgba(0,0,0,0.3);
        }

        /* 右侧的书页边缘层次感 */
        .history-scroll::after {
            content: '';
            position: absolute;
            right: 0;
            top: 0;
            bottom: 0;
            width: 5px;
            background: linear-gradient(to right, rgba(200,180,140,0.4), rgba(234,221,197,0.8), rgba(180,150,110,0.5));
            border-left: 1px solid rgba(180,150,110,0.3);
        }

        /* 顶部布局：只放印章 */
        .header-area {
            display: flex;
            justify-content: flex-start; /* 印章靠左或按需调整 */
            margin-bottom: 10px;
        }

        /* 动态印章基础样式 */
        .stamp {
            display: inline-block;
            border: 2px solid #9e2a2b;
            color: #9e2a2b;
            padding: 4px 10px;
            font-size: 16px;
            font-weight: 900;
            font-family: 'STKaiti', 'KaiTi', serif;
            border-radius: 3px;
            box-shadow: inset 0 0 1px currentColor;
            background: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%"><filter id="n"><feTurbulence type="fractalNoise" baseFrequency="0.8" numOctaves="3" stitchTiles="stitch"/></filter><rect width="100%" height="100%" filter="url(%23n)" opacity="0.15"/></svg>');
            opacity: 0.85;
            user-select: none;
            transform: rotate(-2deg);
            letter-spacing: 1px;
        }

        .stamp.type-wild { border-color: #5c3a4f; color: #5c3a4f; transform: rotate(1deg); }
        .stamp.type-folk { border-color: #3b5c4b; color: #3b5c4b; transform: rotate(-1deg); }

        /* 史书正文：横排 */
        .text-body {
            font-size: 16px;
            line-height: 1.8;
            color: #2b231d;
            letter-spacing: 1px;
            text-align: justify;
        }

        .type-folk-text .text-body { text-align: center; }
        .highlight { color: #8a2525; font-weight: bold; }

        /* 来源出处落款：放在底部右侧 */
        .source-signature {
            font-size: 14px;
            color: #5c4e40;
            font-style: italic;
            text-align: right;
            margin-top: 10px; /* 和正文拉开一点距离 */
        }
    </style>
</head>
<body>

    <div class="history-scroll" id="scroll-container">
        <!-- 左侧装订线孔 -->
        <div class="binding-holes">
            <div class="hole"></div>
            <div class="hole"></div>
            <div class="hole"></div>
        </div>

        <!-- 顶部区域只留印章 -->
        <div class="header-area">
            <div class="stamp" id="ui-stamp">国史纪要</div>
        </div>

        <!-- 正文内容区 -->
        <div class="text-body" id="ui-text">
            是日，大争之世，瓦釜雷鸣。列国连横合纵，烽火不息。有狂客布衣入局，搅弄天下风云。后世评说：<span class="highlight">“苍生何辜，唯此一人独清。”</span>
        </div>

        <!-- 出处落款放在正文下方 -->
        <div class="source-signature" id="ui-source">—— 《太史公书·未名列传》</div>
    </div>

    <script>
        /* ========== 获取消息内容 ========== */
        function getMessageData() {
            try {
                var chatMessages = getChatMessages(getCurrentMessageId());
                if (!chatMessages || chatMessages.length === 0) return null;
                return chatMessages[0].message;
            } catch (e) {
                return null;
            }
        }

        /* ========== 解析数据 ========== */
        function parseData(messageText) {
            var result = { type: '', content: '', source: '' };
            if (!messageText) return result;

            var tagMatch = messageText.match(/<history_record>([\s\S]*?)<\/history_record>/);
            if (!tagMatch || !tagMatch[1]) return result;

            var lines = tagMatch[1].trim().split('\n');
            lines.forEach(function(line) {
                var kv = line.split(':');
                if (kv.length === 1 && line.indexOf('：') !== -1) kv = line.split('：');
                if (kv.length >= 2) {
                    var key = kv[0].trim();
                    var value = kv.slice(1).join(':').trim();
                    if (kv.length > 2 && line.indexOf('：') !== -1 && line.indexOf(':') === -1) {
                         value = kv.slice(1).join('：').trim();
                    }
                    if (key === '类型') result.type = value;
                    if (key === '内容') result.content = value;
                    if (key === '出处') result.source = value;
                }
            });
            return result;
        }

        /* ========== 动态配置印章与样式 ========== */
        function applyStampStyle(typeStr) {
            var stampEl = document.getElementById('ui-stamp');
            var containerEl = document.getElementById('scroll-container');
            stampEl.className = 'stamp';
            containerEl.classList.remove('type-folk-text');

            if (!typeStr) { stampEl.innerText = '国史纪要'; return; }

            if (typeStr.indexOf('童谣') !== -1) {
                stampEl.innerText = '民间采风';
                stampEl.classList.add('type-folk');
                containerEl.classList.add('type-folk-text');
            } else if (typeStr.indexOf('民间') !== -1 || typeStr.indexOf('传闻') !== -1) {
                stampEl.innerText = '市井流言';
                stampEl.classList.add('type-folk');
            } else if (typeStr.indexOf('野史') !== -1 || typeStr.indexOf('稗官') !== -1) {
                stampEl.innerText = '稗官野史';
                stampEl.classList.add('type-wild');
            } else if (typeStr.indexOf('竹林') !== -1 || typeStr.indexOf('秘辛') !== -1) {
                stampEl.innerText = '机密卷宗';
                stampEl.classList.add('type-wild');
            } else {
                stampEl.innerText = '国史纪要';
            }
        }

        /* ========== 渲染界面 ========== */
        function renderPage(data) {
            if (data.type || data.content || data.source) {
                applyStampStyle(data.type);
                if (data.content) document.getElementById('ui-text').innerHTML = data.content.replace(/\n/g, '<br>');
                if (data.source) document.getElementById('ui-source').innerHTML = '—— ' + data.source;
            }
        }

        $(function() { renderPage(parseData(getMessageData())); });
    </script>
</body>
</html>
