    crisisRules: {
        allSchools: {
            '儒家': { '圣人': {general:['周室衰微，礼崩乐坏，圣人道统无人尊奉。', '先贤已逝，大儒未起，儒家无公认的“当代圣人”坐镇。']}, '贤人': {general:['诸侯重武力轻文教，贤人不受重用。', '各国卿大夫只问利益，仁政学说被讥为迂阔。']}, '君子': {general:['仕途被世袭贵族垄断，君子难入仕。', '权臣当道，儒家君子多沦为门客。']}, '儒士': {general:['战乱频仍，礼乐典籍散失，无处求学。', '其他学派斥儒为“贱儒”，儒士社会地位下降。']}, '后学': {general:['家境贫寒，束脩难凑，求学无门。', '儒风虽盛，但权贵吝啬，后学常饿肚子。']}},
            '法家': { '立法者': {general:['旧贵族抵制变法，法令难推行。', '立法者触动既得利益，随时可能被清算甚至车裂。']}, '执法官': {general:['执法严苛遭怨恨，人身安全受威胁。', '法家重“刑名”，执法官常被权贵暗杀。']}, '术士': {general:['各国君主多变，术士一朝失宠即死。', '稍有过失便被严惩，甚至被政敌反噬。']}, '法吏': {general:['俸禄微薄，常被上级推诿责任。', '需熟记繁琐律令，错一字即受罚。']}, '学法徒': {general:['各国法律不一，学成无处施展。', '旧贵族打压法家，学法徒被视为“酷吏预备”，遭人歧视。']}},
            '道家': { '真人': {general:['乱世求逍遥，但无处可避兵灾。', '诸侯强征隐士出山，真人被迫卷入政治。']}, '隐士': {general:['山林被侵占，隐居之地难保清静。', '避世学说遭世人指责自私。']}, '论道者': {general:['各国重功利之术，道家清谈无人听。', '名家辩者常来挑战，道家论道者疲于应付。']}, '养生徒': {general:['战乱缺药，丹方难觅。', '方士骗术横行，养生徒常被骗财。']}, '附道民': {general:['天灾人祸，生活困顿，无力修心。', '其他学派抢信徒，附道民摇摆不定。']}},
            '墨家': { '巨子': {general:['墨家内部纪律严苛，巨子一言不合即被挑战。', '各国视墨者为不安分者，巨子常被官府通缉。']}, '钜子副手': {general:['巨子若有变，副手难服众，面临内乱风险。', '强国招揽墨者，副手面临道德压力。']}, '墨者': {general:['生活清苦营养不良，疾病多发。', '日夜操劳，为救弱守城而大量伤亡。']}, '信士': {general:['资助墨家耗费巨大，家财散尽。', '信士若被敌人抓住，常被严刑拷问机密。']}, '学徒': {general: ['训练严酷，体弱者被淘汰。'] }},
            '兵家': { '兵圣': {general:['各国君主功利至上，兵圣功高震主易被猜忌。', '兵家大师难有善终，常被逼出走他国。']}, '名将': {general:['粮草不足，士兵缺编，巧妇难为无米之炊。', '精锐部队耗资巨大，名将常因军费不足而败。']}, '军师': {general:['献计不被采纳，反被指责误国。', '纵横家干扰决策，兵家军师与之频发内斗。']}, '校尉': {general:['兵器老旧，铁甲稀缺，校尉常带头冲锋。', '贵族私兵不听调，校尉指挥不动。']}, '卒士': {general:['军饷拖欠，受伤无人医治。', '战败或逃亡被株连三族，进退皆死。']}},
            '农家': { '后稷之徒': {general:['各国重商轻农，农家学说被忽视。', '农家主张常被法家抄袭，却不承认其地位。']}, '耕战士': {general:['主张“君臣并耕”，被讥为“悖乱”。', '农家学者常被征发修水利，耽误著述。']}, '老农': {general:['铁农具稀缺，耕作效率低，收成不足。', '边地劫掠频发，老农家破人亡。']}, '农丁': {general:['赋税沉重，青壮年被征去打仗，田地荒芜。', '战车争地，农丁的田常被军队踏平。']}, '学徒': {general:['饥荒年月，学徒连饭吃不饱。', '农家技术被官府窃取，学徒被逼去教官营农庄。']}},
