function savePlayClass() {
    if(!userData.playClass) { alert('请选择阶级'); return; }

    renderCards('play-act-cards', worldData.playData.plays, 'play-act-cards', item => {
        const idx = userData.playActs.indexOf(item.name);
        if(idx > -1) { userData.playActs.splice(idx, 1); }
        else { userData.playActs.push(item.name); }

        if(userData.playActs.includes('歌舞') || userData.playActs.includes('女闾')) {
            document.getElementById('play-beauty-section').style.display = 'block';
        } else {
            document.getElementById('play-beauty-section').style.display = 'none';
