function saveSituation() {
    if (!userData.situation) { alert('请选择时代大势'); return; }

    document.getElementById('faction-detail-section').style.display = 'none';
    const factionTypes = [ {name: '诸侯国', desc: '效力于列国庙堂之上'}, {name: '百家', desc: '游走于思想碰撞之中'} ];

    renderCards('faction-type-cards', factionTypes, 'faction-type-cards', item => {
        userData.factionType = item.name;
        document.getElementById('faction-detail-section').style.display = 'block';
        document.getElementById('faction-detail-title').innerText = `选择具体${item.name}`;

        let details = [];
                if(item.name === '诸侯国') {
            const sevenWarringStates = ['魏','齐','楚','燕','赵','韩','秦'];
            const statesToRender = (userData.situation.year >= 403) ? worldData.factions.states : sevenWarringStates;
            details = statesToRender.map(f => ({ name: f, desc: '' }));
            document.getElementById('custom-position-container').style.display = 'flex';
        } else {
            details = worldData.factions.schools.map(f => ({ name: f, desc: '' }));
            // 【新增】把开宗立派和具体百家放在同级
            details.push({ name: '开宗立派', desc: '建立自己的学说与门庭' });
