    goToPage(3);
}

function saveFaction() {
    if (!userData.faction) { alert('请选择具体阵营'); return; }

    // 【新增】如果是开宗立派，直接跳到形式选择，不需要选阶级
    if (userData.faction === '开宗立派') {
        userData.path = '开宗立派';
        goToPage(14);
        return;
    }

    let year = userData.situation.year;
    let classList = [];
    let yearClasses = `classes_${year}`;

    if (worldData[yearClasses] && worldData[yearClasses][userData.faction]) {
        classList = worldData[yearClasses][userData.faction];
    } else if (worldData.classes[userData.faction]) {
        classList = worldData.classes[userData.faction];
    } else {
        classList = [{name: '普通平民', desc: '无固定阶级'}];
    }

    renderCards('class-cards', classList, 'class-cards', item => {
        userData.class = item.name;
        document.getElementById('input-custom-position').placeholder = `默认身份: ${item.name}`;

        const assetsData = worldData.classAssets[item.name] || { name: '寻常生计', income: '100石', expense: '80石' };
        userData.assets = assetsData;
    });

    goToPage(4); // 统一先选出身阶级
}

function saveClass() {
    if (!userData.class) { alert('请选择出身家世'); return; }
    if (userData.factionType === '诸侯国') {
        const customPos = document.getElementById('input-custom-position').value.trim();
        userData.position = customPos || userData.class;
    } else {
        userData.position = userData.class;
    }

    const lowClasses = ['奴隶', '农民', '佃农', '野人', '平民', '后学', '学法徒', '附道民', '学徒', '信士', '卒士', '农丁', '好奇徒', '听客', '记录徒', '习纵连者', '情报员', '信众'];
    const isLowClass = lowClasses.some(c => userData.class.includes(c));

    let reps = [];
    if(isLowClass) {
        reps = worldData.reputationLevels.low.concat(worldData.reputationLevels.high.filter(l => l.name === '默默无闻'));
    } else {
        reps = worldData.reputationLevels.high.concat(worldData.reputationLevels.low);
    }

    const uniqueReps = Array.from(new Set(reps.map(a => a.name))).map(name => reps.find(a => a.name === name));
    renderCards('reputation-cards', uniqueReps, 'reputation-cards', item => { userData.reputation = item.name; });
    goToPage(5);
}

