function updateFounderPresets() {
    const school = document.getElementById('founder-source-school').value;
    if (userData.founderType === '继承') {
        document.getElementById('founder-doctrine').value = presets.doctrine[school] || '';
    } else if (userData.founderType === '分裂') {
        refreshPreset('branch');
        document.getElementById('founder-doctrine').value = (presets.doctrine[school] || '') + '（但在某一点上有了全新突破）';
    }
}

function refreshPreset(type) {
    const el = document.getElementById(`founder-${type}`);
    if(!el) return;
    let list = [];
    if (type === 'desc') list = presets.desc[userData.founderType];
    else if (type === 'power') list = presets.power;
    else if (type === 'branch') {
        const school = document.getElementById('founder-source-school').value;
        list = presets.branch[school] || ['新派', '异流'];
    }
    else if (type === 'doctrine') {
        list = Object.values(presets.doctrine).map(d => "融汇了：" + d);
    }
    el.value = list[Math.floor(Math.random() * list.length)];
}

function updateFounderCities() {
    const state = document.getElementById('founder-state').value;
    const citySelect = document.getElementById('founder-city');
    citySelect.innerHTML = '<option value="" disabled selected>-- 选择城市 --</option>';
    if(!state) return;

    let year = userData.situation.year;
    let cities = [];
    if(worldData.regionsData.special[year] && worldData.regionsData.special[year][state]) {
        cities.push(...worldData.regionsData.special[year][state]);
    }
    if(worldData.regionsData.general[state]) {
        for(let g of worldData.regionsData.general[state]) {
            if(!cities.find(c => c.name === g.name)) cities.push(g);
        }
    }

    cities.forEach(c => {
        citySelect.innerHTML += `<option value="${c.name}">${c.name}</option>`;
    });
}

function saveFounderDetails() {
    const t = userData.founderType;
    let valid = true;

    if (t === '继承' || t === '分裂') {
        userData.founderSource = document.getElementById('founder-source-school').value;
        if(!userData.founderSource) { alert('请选择源流学派'); valid = false; }
        userData.class = '宗师/巨子/首领';
    }
    if (t === '分裂') {
        userData.founderBranch = document.getElementById('founder-branch').value.trim();
    }
    if (t === '另立') {
        userData.founderName = document.getElementById('founder-name').value.trim();
        userData.founderRelation = document.getElementById('founder-relation').value.trim();
        if(!userData.founderName) { alert('请填写学派名称'); valid = false; }
        userData.class = '开派宗师';
    }

    userData.founderDesc = document.getElementById('founder-desc').value.trim();
    userData.founderDoctrine = document.getElementById('founder-doctrine').value.trim();
    userData.reputation = document.getElementById('founder-reputation').value;
    userData.regionState = document.getElementById('founder-state').value;
    userData.regionCity = document.getElementById('founder-city').value;
    userData.founderCustomRegion = document.getElementById('founder-custom-region').value.trim();
        userData.founderPower = document.getElementById('founder-power').value.trim();
    const assetStr = document.getElementById('founder-assets').value;
    const customAssetStr = document.getElementById('founder-custom-asset').value.trim();

    if(!userData.founderDesc) { alert('请填写地位描述'); valid = false; }
    if(!userData.founderDoctrine) { alert('请填写学派主旨'); valid = false; }
    if(!userData.reputation) { alert('请选择声望'); valid = false; }
    if(!userData.regionState || !userData.regionCity) { alert('请选择驻扎国家和城市'); valid = false; }
    if(!userData.founderPower) { alert('请填写学派力量'); valid = false; }
    if(!assetStr && !customAssetStr) { alert('请选择或填写学派资产'); valid = false; } // 【修改】判断预设或自定义

    if(!valid) return;

    userData.region = userData.founderCustomRegion || `${userData.regionState}-${userData.regionCity}`;
    userData.position = '学派领袖';

    // 【修改】处理自定义资产或预设资产
    if (customAssetStr) {
        // 如果用户填写了自定义资产，尝试解析它
        const matches = customAssetStr.match(/产业\((.*?)\)[,，]\s*收入\((.*?)\)[,，]\s*支出\((.*?)\)/);
        if(matches) {
            userData.assets = { name: matches[1], income: matches[2], expense: matches[3] };
        } else {
            // 如果没按格式写，就把整段话塞给产业，收入支出为空
            userData.assets = { name: customAssetStr, income: '未知', expense: '未知' };
        }
    } else {
        // 使用预设资产
        const assetDef = worldData.founderRules.assets.find(a => a.name === assetStr);
        if(assetDef) {
            const matches = assetDef.desc.match(/产业\((.*?)\), 收入\((.*?)\), 支出\((.*?)\)/);
            if(matches) {
                userData.assets = { name: matches[1], income: matches[2], expense: matches[3] };
            }
        }
    }

    let finalName = '';
    if(t === '继承') finalName = userData.founderSource;
    else if(t === '分裂') finalName = userData.founderBranch || `${userData.founderSource}分支`;
    else finalName = userData.founderName;

    userData.force = {
        type: '自立山头',
        name: finalName,
        power: userData.founderPower,
        subordinates: '门下弟子'
    };

    renderTalentPage();
    goToPage(8);
}

function renderRegionPage() {
    document.getElementById('state-select-section').style.display = 'none';
    document.getElementById('official-position-section').style.display = 'none';
    document.getElementById('companion-select-section').style.display = 'none';
    document.getElementById('custom-region-container').style.display = 'none';

    let year = userData.situation.year;

    function getMergedRegions(factionName) {
        let merged = [];
        if (worldData.regionsData.special[year] && worldData.regionsData.special[year][factionName]) {
            merged.push(...worldData.regionsData.special[year][factionName]);
        }
        if (worldData.regionsData.general[factionName]) {
            let gen = worldData.regionsData.general[factionName];
            for (let g of gen) {
                if (!merged.find(r => r.name === g.name)) {
                    merged.push(g);
                }
            }
        }
        if (merged.length === 0) merged = [{name: '中原', desc: '四战之地，风云际会'}];
        return merged;
    }

    if (userData.factionType === '诸侯国') {
        document.getElementById('region-title').innerText = '所在地域';
        let regions = getMergedRegions(userData.faction);
        renderCards('region-cards', regions, 'region-cards', item => { userData.region = item.name; });
    }
    else if (userData.factionType === '百家' && userData.path === '入仕') {
        document.getElementById('state-select-section').style.display = 'block';
        document.getElementById('official-position-section').style.display = 'block';
        document.getElementById('region-title').innerText = '任职地域';

        const qiqi = ['魏','齐','楚','燕','赵','韩','秦'];
        const stateData = qiqi.map(s => ({name: s, desc: ''}));
        renderCards('state-cards', stateData, 'state-cards', item => {
            userData.serveState = item.name;
            let regions = getMergedRegions(item.name);
            renderCards('region-cards', regions, 'region-cards', r => { userData.region = r.name; });
        });
        document.getElementById('region-cards').innerHTML = '<div style="color:var(--text-muted); grid-column: 1/-1;">请先选择入仕之国</div>';
    }
    else if (userData.factionType === '百家' && (userData.path === '出游' || userData.path === '论战')) {
        document.getElementById('companion-select-section').style.display = 'block';
        document.getElementById('custom-region-container').style.display = 'block';

        if (userData.path === '论战') {
            document.getElementById('region-title').innerText = '论战都会';
            let weiCity = (year <= 386) ? '安邑' : '大梁';
            let qinCity = (year <= 386) ? '雍城' : '咸阳';
            let hanCity = (year <= 403) ? '平阳' : '新郑';

            let debateRegions = [
                {name: '大梁', desc: '魏国名镇，贤士云集'},
                {name: '临淄', desc: '稷下学宫，百家争鸣'},
                {name: '郢都', desc: '楚国中枢，南北交汇'},
                {name: '蓟城', desc: '燕国都城，北地风云'},
                {name: '邯郸', desc: '赵都繁华，纵横交锋'},
                {name: hanCity, desc: '韩国枢纽，术治之渊'},
                {name: qinCity, desc: '秦国重镇，法理之争'}
            ];
            renderCards('region-cards', debateRegions, 'region-cards', item => { userData.region = item.name; });
        } else {
            document.getElementById('region-title').innerText = '周游大区';
            let travelRegions = [
                {name: '中原 (魏)', desc: '四战之地，交通要冲'},
                {name: '海岱 (齐)', desc: '海滨盐铁，物产丰饶'},
                {name: '江汉 (楚)', desc: '云梦大泽，水网密布'},
                {name: '幽冀 (燕)', desc: '苦寒北地，胡汉杂居'},
                {name: '太行 (赵)', desc: '表里山河，险关要塞'},
                {name: '三川 (韩)', desc: '扼守黄河，铁矿遍布'},
                {name: '关中 (秦)', desc: '八百里秦川，王霸之基'}
            ];
            renderCards('region-cards', travelRegions, 'region-cards', item => { userData.region = item.name; });
        }

        let compData = worldData.schoolCompanions[userData.faction];
        let comps = [];
        if(compData) {
            if(compData.special[year]) comps.push(...compData.special[year]);
            if(comps.length < 2 && compData.general) {
                for(let g of compData.general) { if(comps.length < 2 && !comps.find(c => c.name === g.name)) comps.push(g); }
            }
            if(comps.length < 2 && compData.fallback) {
                for(let f of compData.fallback) { if(comps.length < 2 && !comps.find(c => c.name === f.name)) comps.push(f); }
            }
        }
        if(comps.length === 0) comps = [{name: '无名士人', desc: '志同道合者'}, {name:'乡野路人', desc:'萍水相逢'}];

        userData.selectedCompanions = [];
        renderCards('travel-companion-cards', comps, 'travel-companion-cards', item => {
            const idx = userData.selectedCompanions.indexOf(item.name);
            if(idx > -1) { userData.selectedCompanions.splice(idx, 1); }
            else {
                if(userData.selectedCompanions.length >= 2) {
                    alert('最多选择2位同行者');
                    const cards = document.querySelectorAll('#travel-companion-cards .card');
                    cards.forEach(c => { if(c.innerText.includes(item.name)) c.classList.remove('selected'); });
                    return;
                }
                userData.selectedCompanions.push(item.name);
            }
        }, true);
    }
}

