function renderTalentPage() {
    const container = document.getElementById('talent-selection-area');
    container.innerHTML = '';
    if(!userData.talents) userData.talents = {};
    worldData.talents.forEach(talent => {
        const group = document.createElement('div'); group.className = 'talent-slider-group';
        const header = document.createElement('div'); header.className = 'talent-header';
        header.innerHTML = `<div class="talent-name-desc"><div class="talent-name">${talent.key}</div></div>`;
        const valDisp = document.createElement('div'); valDisp.className = 'talent-value-display';

        let initialName = talent.thresholds.find(t => 0 >= t.val)?.name || '';

        const badge = document.createElement('div'); badge.className = 'talent-title-badge'; badge.innerText = initialName;
        const input = document.createElement('input'); input.className = 'talent-number-input'; input.type = 'number'; input.min = -100; input.max = 100;
        input.value = userData.talents[talent.key] || 0;
        valDisp.appendChild(badge); valDisp.appendChild(input); header.appendChild(valDisp);
        const slider = document.createElement('input'); slider.className = 'talent-slider'; slider.type = 'range'; slider.min = -100; slider.max = 100;
        slider.value = userData.talents[talent.key] || 0;

        const update = (v) => {
            let num = Math.min(100, Math.max(-100, parseInt(v)||0));
            slider.value = num; input.value = num; userData.talents[talent.key] = num;
            let tName = talent.thresholds[0].name;
            for(let th of talent.thresholds) { if(num >= th.val) { tName = th.name; break; } }
            badge.innerText = tName;
        };
        slider.oninput = e => update(e.target.value);
        input.oninput = e => update(e.target.value);

        update(userData.talents[talent.key] || 0);
        group.appendChild(header); group.appendChild(slider); container.appendChild(group);
    });
}

