}

function generateAndGoToCrisis() {
    let crisesList = [];
    let rulesTarget;
    let targetFaction = userData.faction;
    let targetClass = userData.class;
    let year = userData.situation.year;

    if (userData.path === '开宗立派') {
        let school = userData.founderSource || '新学';
        if(userData.founderType === '另立') school = '新学';

        let schoolCrisis = worldData.crisisRules.allSchools[school];
        if(schoolCrisis && schoolCrisis['巨子']) {
             generatedCrises = [...schoolCrisis['巨子'].general];
        } else {
             generatedCrises = ['学派初立，遭到其他显学的联合绞杀与排挤。', '门下弟子良莠不齐，有人打着学派名号在外惹是生非。', '诸侯对新学说充满警惕，下令驱逐学派门徒。'];
        }

        if (userData.founderType === '分裂') {
            generatedCrises.push('源流学派视你为叛徒，派出刺客清理门户。');
        } else if (userData.founderType === '继承') {
            generatedCrises.push('学派内部仍有不服者，暗中图谋篡夺领袖之位。');
        }

    } else {
        if (userData.factionType === '百家' && userData.path === '入仕') {
            rulesTarget = worldData.crisisRules.allStates[userData.serveState];
            targetClass = '新兴官僚（士）';
            targetFaction = userData.serveState;
        } else if (userData.factionType === '百家' && (userData.path === '出游' || userData.path === '论战')) {
            rulesTarget = worldData.crisisRules.allSchools[userData.faction];
        } else {
            rulesTarget = worldData.crisisRules.allStates[userData.faction];
        }

        var generatedCrises = [];

        if(worldData.crisisRules.crisis_year[year] && worldData.crisisRules.crisis_year[year][targetFaction] && worldData.crisisRules.crisis_year[year][targetFaction][targetClass]) {
            generatedCrises.push(worldData.crisisRules.crisis_year[year][targetFaction][targetClass]);
        }

        if (userData.factionType === '百家' && userData.path === '论战') {
            generatedCrises.push('论战逢败：在辩论中被政敌或他派学者驳倒，声名扫地。');
            generatedCrises.push('性命之忧：言辞触怒当地权贵，面临被暗杀或驱逐的风险。');
        }

        if (rulesTarget && rulesTarget[targetClass] && rulesTarget[targetClass].general) {
            for(let g of rulesTarget[targetClass].general) {
                if(generatedCrises.length < 3 && !generatedCrises.includes(g)) generatedCrises.push(g);
            }
        }
        if(generatedCrises.length < 2) {
            for(let f of worldData.crisisRules.fallback) {
                if(generatedCrises.length < 3 && !generatedCrises.includes(f)) generatedCrises.push(f);
            }
        }
    }

    generatedCrises.forEach(desc => {
        crisesList.push({name: desc, desc: ''});
    });
    crisesList.push({name: '自定义', desc: '自行输入面临的具体困境'});

    userData.selectedCrises = [];
    renderCards('crisis-cards', crisesList, 'crisis-cards', item => {
        if(item.name === '自定义') {
            const customDetails = document.getElementById('crisis-custom-details');
            customDetails.style.display = 'flex';
            userData.selectedCrises = ['自定义'];
        } else {
            document.getElementById('crisis-custom-details').style.display = 'none';
            userData.selectedCrises = [item.name];
        }
    }, false);

    goToPage(12);
}

